public class EnumSwitch {
    enum Color { RED, GREEN, BLUE }
    static String label(Color c) {
        return switch (c) {
            case RED   -> "stop";
            case GREEN -> "go";
            case BLUE  -> "sky";
        };
    }
    public static void main(String[] args) {
        for (Color c : Color.values())
            System.out.println(label(c));
    }
}
